// 이 코드는 n8n/hmac-verify.js를 복붙한 것입니다. 원본 수정 시 동기화 필요.
const crypto = require('crypto');
const WEBHOOK_SECRET = $env.WEBHOOK_SHARED_SECRET ?? $vars?.WEBHOOK_SHARED_SECRET ?? '';
if (!WEBHOOK_SECRET) throw new Error('WEBHOOK_SHARED_SECRET 미설정');

const input = $input.item.json ?? {};
const headers = input.headers ?? {};
const signature = headers['x-webhook-signature'] ?? headers['X-Webhook-Signature'] ?? '';
if (!signature) throw new Error('X-Webhook-Signature 헤더 누락');

let bodyStr;
const binary = $input.item.binary?.data;
if (binary?.data) {
  bodyStr = Buffer.from(binary.data, 'base64').toString('utf8');
} else if (typeof input.body === 'string') {
  bodyStr = input.body;
} else if (input.body && typeof input.body === 'object') {
  bodyStr = JSON.stringify(input.body);
} else {
  bodyStr = JSON.stringify(input);
}

const expected = crypto.createHmac('sha256', WEBHOOK_SECRET).update(bodyStr, 'utf8').digest('hex');
const a = Buffer.from(signature, 'hex');
const b = Buffer.from(expected, 'hex');
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error(`HMAC 불일치 got=${signature.slice(0,12)}... expected=${expected.slice(0,12)}...`);
}
const payload = typeof input.body === 'object' ? input.body : JSON.parse(bodyStr);
return [{ json: payload }];

// Claude ReportInput 구성 (5개 Sonnet 호출 공통 입력)
// n8n/claude-prompts.js 의 buildSonnetRequest에 전달할 형식.
const p = $input.item.json;
const currentDate = new Date().toISOString().slice(0, 10);
const currentYear = new Date().getFullYear();

const reportInput = {
  order_number: p.order_number,
  user: {
    name: p.user?.name ?? (p.saju_data?.name) ?? '고객',
    gender: p.user?.gender ?? p.saju_data?.birthGender ?? 'male',
    birth_date: p.user?.birth_date ?? p.saju_data?.birthDate ?? null,
    birth_time: p.user?.birth_hour ?? p.saju_data?.birthTime ?? '자시',
  },
  current_year: currentYear,
  current_date: currentDate,
};

if (!reportInput.user.birth_date) {
  throw new Error('birth_date 없음. Edge Function payload 확인 필요.');
}

return [{
  json: {
    order_id: p.order_id,
    order_number: p.order_number,
    callback: p.callback,
    report_input: reportInput,
  },
}];

// ═════════════════════════════════════════════════════════════════
// n8n/claude-prompts.js 의 핵심 함수만 인라인
// (원본 수정 시 이 블록도 반드시 동기화)
// ═════════════════════════════════════════════════════════════════
const MODEL_SONNET = 'claude-sonnet-4-6';
const BANNED = ['퓨처매핑','Future Mapping','면역맵','Immunity Map','120% 행복','120% happy','STEP 1','STEP 2','STEP 3','STEP 4','STEP 5','STEP 6'];
const FT_TERMS = ['Fortune Score','GROW 4법','발굴 세션','운명 흐름','수확 장면','지금 목소리','실행 브레이크','첫 싹','First Sprout'];

const SYSTEM_PROMPT = `당신은 한국 전통 사주명리학에 깊이 있는 해석가입니다.
동양 명리(사주팔자·십신·신살·대운)를 기반으로, 개인의 구체적 상황에 닿는 조언을 합니다.

[해석 원칙]
1. 단정적 예언 금지. "~할 수 있습니다", "~하는 경향이 있습니다" 식으로 개연성 표현.
2. 사주 분석은 참고 용도이며 전문 상담/의료/법률 결정을 대체하지 않음.
3. 부정적 프레임 회피. 어려움도 "어떻게 활용할 것인가"로.
4. 구체적 실천 가능한 조언. 추상적 미사여구 지양.
5. 한국어 경어체. 독자를 "당신"으로.

[금지어]
${BANNED.map(t=>`- "${t}"`).join('\n')}

[FortuneTab 독자 용어 권장]
${FT_TERMS.map(t=>`- ${t}`).join('\n')}

[출력 규칙]
- 반드시 JSON 객체 하나만. 마크다운/코드펜스/설명 금지.
- 모든 텍스트는 한국어. 한자 병기 가능 (예: "庚申(경신)").
- 문장 완결형.`;

function buildProfileBlock(input) {
  const { user, current_year, current_date } = input;
  const timeKo = typeof user.birth_time === 'number' ? `${user.birth_time}시 (24시간제)` : user.birth_time;
  const genderKo = user.gender === 'male' ? '남자' : '여자';
  return `[분석 대상]\n- 이름: ${user.name}\n- 성별: ${genderKo}\n- 생년월일: ${user.birth_date} (양력)\n- 출생 시간: ${timeKo}\n\n[기준 시점]\n- 올해: ${current_year}년\n- 오늘: ${current_date}\n\n[필수 계산 — 해석 전 내부에서]\n1. 양력 ${user.birth_date} ${timeKo} 사주팔자 계산 (절기·자시 구분).\n2. 일간 확정, 오행 분포, 용신 후보.\n3. 대운 배열 + 현재 나이 대운 + 올해 세운.`;
}

// 각 섹션 프롬프트 (축약본 · 원본은 claude-prompts.js 참조)
const SECTION_PROMPTS = {
  saju_core: `[작업] 이 사람의 사주 구조 분석.\n[출력 JSON]\n{\n  "four_pillars": {"year":{"hj":"","ko":"","element":""},"month":{...},"day":{...},"hour":{...}|null},\n  "day_master": {"stem":"","element":"","strength":"신강|신약|중화","description":"2-3문장"},\n  "five_elements": {"wood":0,"fire":0,"earth":0,"metal":0,"water":0},\n  "yongsin": {"element":"","reason":"1-2문장"},\n  "sipsin_highlight": [{"position":"","name":"","meaning":""}],\n  "narrative": "500자 내외"\n}`,
  annual_outlook: `[작업] 현재 대운 10년 + 올해 세운 분석.\n[출력 JSON]\n{\n  "current_daeun": {"period":"","pillar_hj":"","pillar_ko":"","theme":"","opportunities":[],"challenges":[],"transition_signs":""},\n  "next_daeun_preview": {"period":"","pillar_hj":"","one_line":""},\n  "annual_flow": {"year":2026,"seun_pillar":"","theme":"","quarters":{"q1":"","q2":"","q3":"","q4":""},"key_months":[{"month":0,"why":"","action":""}]},\n  "narrative": "600자 내외"\n}`,
  monthly_seun: `[작업] 1~12월 세운 분석. months 배열 정확히 12개.\n[출력 JSON]\n{"months":[{"month":1,"seun_pillar_ko":"","energy":"20자 이내","focus":"","watch_out":"","keyword":"2-4자","color_tone":""}]}`,
  action_guide: `[작업] GROW 4법 실행 가이드.\n[출력 JSON]\n{\n  "grow_four":{"goal":{"title":"","items":[]},"reality":{"title":"","items":[]},"options":{"title":"","items":[]},"will":{"title":"","items":[]}},\n  "weekly_habits":[{"day":"","habit":""}],\n  "first_sprout":"3분 이내 실행 가능한 1문장"\n}`,
  insight_highlight: `[작업] TOP 3 통찰 + 경고 + 한 줄 요약.\n[출력 JSON]\n{\n  "top_insights":[{"title":"12자 이내","body":"100자 내외"}],\n  "watchouts":[{"area":"","caution":"","timing":""}],\n  "one_line":"30자 이내"\n}`,
};

function buildSonnetRequest(section, input) {
  return {
    model: MODEL_SONNET,
    max_tokens: section === 'monthly_seun' ? 8000 : 5000,
    temperature: 0.7,
    system: [
      { type: 'text', text: SYSTEM_PROMPT },
      { type: 'text', text: buildProfileBlock(input), cache_control: { type: 'ephemeral' } },
    ],
    messages: [{ role: 'user', content: SECTION_PROMPTS[section] }],
  };
}

const input = $input.item.json.report_input;
const sections = ['saju_core', 'annual_outlook', 'monthly_seun', 'action_guide', 'insight_highlight'];

return sections.map(s => ({
  json: {
    section: s,
    order_id: $input.item.json.order_id,
    order_number: $input.item.json.order_number,
    callback: $input.item.json.callback,
    request: buildSonnetRequest(s, input),
  },
}));

// 5개 Sonnet 응답 집계 (HTTP Request가 input을 덮어쓰므로 원본 참조로 section 매칭)
const apiResps = $input.all();
const origs = $('5개 Sonnet 요청 생성').all();

const sections = {};
let orderId = null, orderNumber = null, callback = null;

function extractJson(text) {
  // 1) 코드펜스 제거
  let t = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  // 2) 첫 { 부터 마지막 } 까지 탐욕 추출 (앞뒤 prose 무시)
  const s = t.indexOf('{');
  const e = t.lastIndexOf('}');
  if (s === -1 || e === -1 || e <= s) throw new Error('JSON 블록 없음');
  return JSON.parse(t.slice(s, e + 1));
}

for (let i = 0; i < apiResps.length; i++) {
  const section = origs[i]?.json?.section ?? `unknown-${i}`;
  orderId = origs[i]?.json?.order_id ?? orderId;
  orderNumber = origs[i]?.json?.order_number ?? orderNumber;
  callback = origs[i]?.json?.callback ?? callback;

  const api = apiResps[i].json;
  const text = api.content?.[0]?.text ?? api.body?.content?.[0]?.text ?? '';
  if (!text) throw new Error(`섹션 '${section}' 응답 text 없음. api keys=${Object.keys(api).join(',')}`);

  try {
    sections[section] = extractJson(text);
  } catch (err) {
    throw new Error(`섹션 '${section}' 파싱 실패: ${err.message}\n응답 앞 300자: ${text.slice(0, 300)}`);
  }
}

return [{ json: { order_id: orderId, order_number: orderNumber, callback, sections } }];

// Haiku 검수 요청 생성
const MODEL_HAIKU = 'claude-haiku-4-5-20251001';
const BANNED = ['퓨처매핑','Future Mapping','면역맵','Immunity Map','120% 행복','120% happy'];

const HAIKU_SYSTEM = `당신은 FortuneTab 리포트 편집 검수자입니다.
[검증] 1) 금지어 [${BANNED.join(', ')}] 교체  2) 단정적 예언 완화  3) 스키마 유효성  4) monthly_seun 12개  5) top_insights 3개
[출력 JSON only]
{"ok":true|false,"issues":[{"section":"","problem":"","severity":"low|med|high"}],"fixed_sections":{}}`;

const sections = $input.item.json.sections;
const userPrompt = `[검수 대상]\n${JSON.stringify(sections, null, 2)}`;

return [{
  json: {
    order_id: $input.item.json.order_id,
    order_number: $input.item.json.order_number,
    callback: $input.item.json.callback,
    sections,
    request: {
      model: MODEL_HAIKU,
      max_tokens: 8000,
      temperature: 0.2,
      system: HAIKU_SYSTEM,
      messages: [{ role: 'user', content: userPrompt }],
    },
  },
}];

// Haiku 결과 적용 + 최종 섹션 확정
const apiResp = $input.item.json;
const text = apiResp.content?.[0]?.text ?? '';
const cleaned = text.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();

let review = { ok: true, fixed_sections: {}, issues: [] };
try { review = JSON.parse(cleaned); }
catch (e) { console.warn('[haiku-review] 파싱 실패, 원본 섹션 사용:', e.message); }

const prev = $('Haiku 검수 요청 생성').first().json;
const merged = { ...prev.sections, ...(review.fixed_sections ?? {}) };

return [{
  json: {
    order_id: prev.order_id,
    order_number: prev.order_number,
    callback: prev.callback,
    review_issues: review.issues ?? [],
    sections: merged,
  },
}];

// pdf_server /reports/render 요청 페이로드 구성
const s = $input.item.json.sections;
const orig = $('ReportInput 구성').first().json.report_input;

const payload = {
  order_id: $input.item.json.order_id,
  order_number: $input.item.json.order_number,
  user: orig.user,
  meta: {
    current_year: orig.current_year,
    issued_at: new Date().toLocaleDateString('ko-KR', { year:'numeric', month:'long', day:'numeric' }),
  },
  saju_core: s.saju_core,
  annual_outlook: s.annual_outlook,
  monthly_seun: s.monthly_seun,
  action_guide: s.action_guide,
  insight_highlight: s.insight_highlight,
};

return [{
  json: {
    order_id: $input.item.json.order_id,
    order_number: $input.item.json.order_number,
    callback: $input.item.json.callback,
    sections: s,
    review_issues: $input.item.json.review_issues,
    render_payload: payload,
  },
}];

// readWriteFile 노드 대체 — Code 노드에서 직접 fs.writeFileSync
// n8n 1.x readWriteFile의 'not writable' 우회. /reports는 호스트 /volume1/docker/fortunetab/reports 마운트됨.
const fs = require('fs');
const path = require('path');

const orderId = $input.item.json.order_id;
if (!orderId) throw new Error('order_id 없음');

// n8n Code 노드 헬퍼: binary를 Buffer로 가져옴
const buf = await this.helpers.getBinaryDataBuffer(0, 'pdf');
if (!buf || buf.length < 1000) {
  throw new Error(`PDF 바이너리 이상: size=${buf?.length ?? 0}`);
}

const filePath = `/reports/${orderId}.pdf`;
fs.writeFileSync(filePath, buf);

return [{
  json: {
    ...$input.item.json,
    nas_file_path: filePath,
    nas_bytes: buf.length,
  },
}];

// Supabase REST PATCH 페이로드 (orders.report_file_url + report_json)
const order_id = $('렌더 페이로드 구성').first().json.order_id;
const sections = $('렌더 페이로드 구성').first().json.sections;
const reviewIssues = $('렌더 페이로드 구성').first().json.review_issues;

// NAS 파일의 외부 접근 URL — 사용자 환경 맞춤 (예: 리버스 프록시 /r/<order>.pdf)
const NAS_PUBLIC_BASE = $env.NAS_REPORT_PUBLIC_BASE ?? 'https://reports.fortunetab.com/r';
const publicUrl = `${NAS_PUBLIC_BASE}/${order_id}.pdf`;

return [{
  json: {
    order_id,
    callback: $('렌더 페이로드 구성').first().json.callback,
    patch_body: {
      report_file_url: publicUrl,
      report_json: { ...sections, _review_issues: reviewIssues ?? [] },
    },
  },
}];
